'use strict';

const fs = require('fs');
const path = require('path');

// Shiki v1 registers custom grammars under grammar.name (e.g. "lcc"), NOT
// grammar.scopeName (e.g. "source.lcc"). Any codeToHtml({ lang: ... }) call
// must use the name value — scopeName silently fails on cold (uncached) loads.
//
// The deployed Sandbox at /sandbox/ is GENERATED by scripts/build-site.js
// (docs/site/sandbox/index.html); the former standalone source pages
// docs/showcase/index.html + docs/playground/index.html were removed in #1045
// so fixes can no longer land on a non-deployed copy. Assert the invariant on
// the generator, which is the surface that actually ships.
test('build-site.js uses lang: lcc not lang: source.lcc in codeToHtml calls', () => {
  const src = fs.readFileSync(
    path.join(__dirname, '../../scripts/build-site.js'), 'utf8'
  );
  expect(src).not.toMatch(/lang:\s*['"]source\.lcc['"]/);
  expect(src).toMatch(/lang:\s*['"]lcc['"]/);
});
